import {
  useKeyboardShortcuts,
  formatShortcut,
  COMMON_SHORTCUTS,
  type KeyboardShortcutConfig,
} from '@hooks/useKeyboardShortcuts';

// ============================================================
// Unit tests for formatShortcut
// ============================================================
describe('formatShortcut', () => {
  it('should format simple key', () => {
    expect(formatShortcut({ key: 'a' })).toBe('A');
  });

  it('should format Ctrl+key', () => {
    expect(formatShortcut({ key: 'z', ctrl: true })).toBe('Ctrl+Z');
  });

  it('should format Ctrl+Shift+key', () => {
    expect(formatShortcut({ key: 'z', ctrl: true, shift: true })).toBe('Ctrl+Shift+Z');
  });

  it('should format Alt+key', () => {
    expect(formatShortcut({ key: 'f', alt: true })).toBe('Alt+F');
  });

  it('should format complex combo', () => {
    expect(formatShortcut({ key: 's', ctrl: true, shift: true, alt: true })).toBe('Ctrl+Shift+Alt+S');
  });

  it('should handle meta key', () => {
    expect(formatShortcut({ key: 's', meta: true })).toBe('Ctrl+S');
  });

  it('should handle key only (no modifiers)', () => {
    expect(formatShortcut({ key: 'Delete' })).toBe('DELETE');
  });

  it('should handle empty', () => {
    expect(formatShortcut({})).toBe('');
  });
});

