// ============================================================
// Unit tests for shortcut matching logic
// ============================================================
describe('Shortcut matching logic', () => {
  // Helper to create KeyboardEvent-like objects
  function createKeyEvent(overrides: Partial<KeyboardEvent>): KeyboardEvent {
    return {
      key: '',
      ctrlKey: false,
      shiftKey: false,
      altKey: false,
      metaKey: false,
      preventDefault: jest.fn(),
      stopPropagation: jest.fn(),
      target: document.createElement('div'),
      ...overrides,
    } as unknown as KeyboardEvent;
  }

  // Simulate the matching logic from useKeyboardShortcuts
  function matchesShortcut(event: KeyboardEvent, shortcut: Partial<KeyboardShortcutConfig>): boolean {
    const keyMatch = shortcut.key?.toLowerCase() === event.key.toLowerCase();
    const ctrlMatch = shortcut.ctrl === undefined || shortcut.ctrl === (event.ctrlKey || event.metaKey);
    const shiftMatch = shortcut.shift === undefined || shortcut.shift === event.shiftKey;
    const altMatch = shortcut.alt === undefined || shortcut.alt === event.altKey;
    const metaMatch = shortcut.meta === undefined || shortcut.meta === event.metaKey;

    return Boolean(keyMatch && ctrlMatch && shiftMatch && altMatch && metaMatch);
  }

  it('should match Ctrl+Z for undo', () => {
    const event = createKeyEvent({ key: 'z', ctrlKey: true });
    expect(matchesShortcut(event, COMMON_SHORTCUTS.UNDO)).toBe(true);
  });

  it('should match Ctrl+Shift+Z for redo', () => {
    const event = createKeyEvent({ key: 'z', ctrlKey: true, shiftKey: true });
    expect(matchesShortcut(event, COMMON_SHORTCUTS.REDO_Z)).toBe(true);
  });

  it('should NOT match Ctrl+Z for redo', () => {
    const event = createKeyEvent({ key: 'z', ctrlKey: true, shiftKey: false });
    expect(matchesShortcut(event, COMMON_SHORTCUTS.REDO_Z)).toBe(false);
  });

  it('should match Delete key', () => {
    const event = createKeyEvent({ key: 'Delete' });
    expect(matchesShortcut(event, COMMON_SHORTCUTS.DELETE)).toBe(true);
  });

  it('should match Space for play/pause', () => {
    const event = createKeyEvent({ key: ' ' });
    expect(matchesShortcut(event, COMMON_SHORTCUTS.PLAY_PAUSE)).toBe(true);
  });

  it('should match Ctrl+S for save', () => {
    const event = createKeyEvent({ key: 's', ctrlKey: true });
    expect(matchesShortcut(event, COMMON_SHORTCUTS.SAVE)).toBe(true);
  });

  it('should match metaKey as ctrl', () => {
    const event = createKeyEvent({ key: 'z', metaKey: true });
    expect(matchesShortcut(event, COMMON_SHORTCUTS.UNDO)).toBe(true);
  });

  it('should NOT match plain Z without ctrl', () => {
    const event = createKeyEvent({ key: 'z' });
    // UNDO requires ctrl: true, but matchesShortcut checks ctrl === (ctrlKey || metaKey)
    // ctrlKey = false, metaKey = false, so (false || false) = false !== true
    expect(matchesShortcut(event, COMMON_SHORTCUTS.UNDO)).toBe(false);
  });

  it('should match Escape for deselect', () => {
    const event = createKeyEvent({ key: 'Escape' });
    expect(matchesShortcut(event, COMMON_SHORTCUTS.DESELECT)).toBe(true);
  });

  it('should match Ctrl+D for duplicate', () => {
    const event = createKeyEvent({ key: 'd', ctrlKey: true });
    expect(matchesShortcut(event, COMMON_SHORTCUTS.DUPLICATE)).toBe(true);
  });
});

// ============================================================
// Unit tests for input field exclusion logic
// ============================================================
describe('Input field exclusion', () => {
  function isInputTarget(target: HTMLElement): boolean {
    return (
      target.tagName === 'INPUT' ||
      target.tagName === 'TEXTAREA' ||
      target.contentEditable === 'true'
    );
  }

  it('should detect INPUT elements', () => {
    const input = document.createElement('input');
    expect(isInputTarget(input)).toBe(true);
  });

  it('should detect TEXTAREA elements', () => {
    const textarea = document.createElement('textarea');
    expect(isInputTarget(textarea)).toBe(true);
  });

  it('should detect contentEditable elements', () => {
    const div = document.createElement('div');
    div.contentEditable = 'true';
    expect(isInputTarget(div)).toBe(true);
  });

  it('should NOT detect regular DIV', () => {
    const div = document.createElement('div');
    expect(isInputTarget(div)).toBe(false);
  });

  it('should NOT detect regular BUTTON', () => {
    const button = document.createElement('button');
    expect(isInputTarget(button)).toBe(false);
  });

  it('should NOT detect CANVAS', () => {
    const canvas = document.createElement('canvas');
    expect(isInputTarget(canvas)).toBe(false);
  });
});

// ============================================================
// KeyboardShortcutConfig type structure tests
// ============================================================
describe('KeyboardShortcutConfig structure', () => {
  it('should create valid shortcut config', () => {
    const config: KeyboardShortcutConfig = {
      key: 's',
      ctrl: true,
      callback: jest.fn(),
      description: 'Save',
      preventDefault: true,
    };

    expect(config.key).toBe('s');
    expect(config.ctrl).toBe(true);
    expect(config.description).toBe('Save');
    expect(config.preventDefault).toBe(true);
  });

  it('should allow optional modifiers', () => {
    const config: KeyboardShortcutConfig = {
      key: 'Delete',
      callback: jest.fn(),
      description: 'Delete element',
    };

    expect(config.ctrl).toBeUndefined();
    expect(config.shift).toBeUndefined();
    expect(config.alt).toBeUndefined();
    expect(config.meta).toBeUndefined();
  });

  it('should have callable callback', () => {
    const callback = jest.fn();
    const config: KeyboardShortcutConfig = {
      key: 'a',
      ctrl: true,
      callback,
      description: 'Select all',
    };

    config.callback();
    expect(callback).toHaveBeenCalledTimes(1);
  });
});
